def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        weight = 1.0
        complexity = 0.0
        for j in range(1, 15):
            if j % 3 == 0 and j % 5 == 0:
                weight *= 1.12
            elif j % 3 == 0:
                weight *= 0.95
            elif j % 5 == 0:
                weight *= 1.08
            if ratio < 0.08 * j:
                score_part = (j ** 2) * np.exp(-ratio * j) * weight
            else:
                score_part = (np.sqrt(j) + np.tanh(ratio * j)) * weight / (j + 2)
            if (cap + j) % 4 == 0:
                score_part *= 1.05
            elif (cap * j) % 7 == 0:
                score_part *= 0.9
            if j % 2 == 0:
                complexity += np.sin(score_part) * np.log1p(j)
            else:
                complexity -= np.cos(score_part) / (j + 1)
            score += score_part
            if j >= 5 and j % 4 == 1:
                for k in range(1, 4):
                    diff = cap - k * item * (j % 3 + 1)
                    if diff > 0:
                        if diff % (k + 2) == 0:
                            complexity += np.sqrt(diff) / (k + j + 1)
                        else:
                            complexity -= np.log1p(abs(diff)) / (k + j)
                    else:
                        complexity -= (abs(diff)) ** 1.3 / (k + j + 2)
        if score + complexity == 0:
            priorities[i] = np.inf
            continue
        combined = score * 0.7 + complexity * 0.3
        if combined < 0:
            val = -combined * np.log1p(cap + item) / (1 + ratio)
        else:
            if cap > item * 3:
                val = -combined / (np.sqrt(cap) + 0.5) * np.tanh(ratio * 2)
            else:
                val = -combined / (cap + 3) * (1 + 0.5 * np.exp(-ratio))
        if ratio > 1:
            val *= 1.15
            if cap % 2 == 0:
                val *= 0.9
        elif ratio < 0.05:
            val *= 0.75
            if cap % 3 == 0:
                val *= 1.1
        if cap % 10 == 0 and ratio < 0.3:
            val *= 1.05
        priorities[i] = val
    return priorities
